import { Outlet, NavLink } from "react-router-dom";

import { createUseStyles } from "react-jss";

const styles = createUseStyles({
  container: {
    display: "flex",
    justifyContent: "flex-end",
    fontSize: "20px",
    listStyle: "none",
    gap: "10px",
  },
  li: {
    textDecoration: "none",
    color: "#3582c5",
    "&:hover": { color: "#dc5b24" },
  },
  active: {
    color: "#dc5b24",
  },
  cont: {
    display: "flex",
  },
});

const Layout = () => {
  const classes = styles();
  return (
    <>
      <div className={classes.cont}>
        <h3>Выбери свой путь</h3>
        <ul className={classes.container}>
          <li>
            <NavLink
              className={({ isActive }) =>
                isActive ? `${classes.active}` : `${classes.li}`
              }
              to="html"
            >
              HTML
            </NavLink>
          </li>
          <li>
            <NavLink
              className={({ isActive }) =>
                isActive ? `${classes.active}` : `${classes.li}`
              }
              to="css"
            >
              CSS
            </NavLink>
          </li>
          <li>
            <NavLink
              className={({ isActive }) =>
                isActive ? `${classes.active}` : `${classes.li}`
              }
              to="Figma"
            >
              Figma
            </NavLink>
          </li>
        </ul>
      </div>
      <Outlet />
    </>
  );
};
export default Layout;
